#include <iostream>
using namespace std;

// Base Class
class Shape {
protected:
    int width, height;
public:
    void setDimensions(int w, int h) {
        width = w;
        height = h;
    }
};

// Derived Class 1
class Rectangle : public Shape {
public:
    int getArea() {
        return width * height;
    }
};

// Derived Class 2
class Triangle : public Shape {
public:
    int getArea() {
        return (width * height) / 2;
    }
};

int main() {
    Rectangle rect;
    rect.setDimensions(5, 7);
    cout << "Rect Area: " << rect.getArea() << endl;

    Triangle tri;
    tri.setDimensions(5, 7);
    cout << "Tri Area: " << tri.getArea() << endl;

    return 0;
}
